const API_BASE_URL = 'https://dev.memate.com.au/api/v1';


export const fetchSales = async () => {
  const myHeaders = new Headers();
  const accessToken = sessionStorage.getItem("access_token");
  myHeaders.append("Authorization", `Bearer ${accessToken}`);

  const requestOptions = {
    method: 'GET',
    headers: myHeaders,
    redirect: 'follow'
  };

  try {
    const response = await fetch(`${API_BASE_URL}/sales/`, requestOptions);
    const result = await response.text();
    return result;
  } catch (error) {
    console.error('Profile fetch error:', error);
    throw error;
  }
};



export const fetchSalesNotes = async (saleUniqueId, updatedNote) => {
  const myHeaders = new Headers();
  const accessToken = sessionStorage.getItem("access_token");
  myHeaders.append("Authorization", `Bearer ${accessToken}`);
  myHeaders.append("Content-Type", "application/json"); 

  const requestOptions = {
    method: 'PUT', 
    headers: myHeaders,
    body: JSON.stringify({ sales_note: updatedNote }), 
    redirect: 'follow',
  };

  try {
    const response = await fetch(`${API_BASE_URL}/sales/${saleUniqueId}/notes/`, requestOptions);

    if (!response.ok) {
      const errorText = await response.text();
      throw new Error(`Sales notes update failed with status ${response.status}: ${errorText}`);
    }

    const result = await response.text(); 

    const parsedResult = result.trim() ? JSON.parse(result) : null;

    return parsedResult;
  } catch (error) {
    console.error('Sales notes update error:', error);
    throw error;
  }
};



export const fetchOutCome = async (saleUniqueId, action) => {
  const myHeaders = new Headers();
  const accessToken = sessionStorage.getItem("access_token");
  myHeaders.append("Authorization", `Bearer ${accessToken}`);
  myHeaders.append("Content-Type", "application/json");

  const requestOptions = {
    method: 'PUT',
    headers: myHeaders,
    body: JSON.stringify({ action }),
    redirect: 'follow'
  };

  try {
    const response = await fetch(`${API_BASE_URL}/sales/${saleUniqueId}/outcome/`, requestOptions);

    if (response.ok) {
      console.log("Row removed successfully");
      return true;
    } else {
      console.log('Error:', response.status);
      return false;
    }
  } catch (error) {
    console.log('Error:', error);
    return false;
  }
};




export const fetchContacts = async (saleUniqueId, formData) => {
  const myHeaders = new Headers();
  const accessToken = sessionStorage.getItem("access_token");
  myHeaders.append("Authorization", `Bearer ${accessToken}`);
  myHeaders.append("Content-Type", "application/json");
  console.log(formData);
  const requestOptions = {
    method: 'POST',
    headers: myHeaders,
    body: JSON.stringify(formData),
    redirect: 'follow'
  };

  try {
    const response = await fetch(`${API_BASE_URL}/sales/${saleUniqueId}/contacts/`, requestOptions);

    if (response.ok) {
      console.log("Row added successfully");
      const responseData = await response.json(); 
      return responseData;
    } else {
      console.log('Error:', response.status);
      return null; 
    }
  } catch (error) {
    console.log('Error:', error);
    return null; 
  }
};

