import React, { useState } from "react";
import { ChevronDown } from "react-bootstrap-icons";
import CircleProgressBar from "./CircleProgressBar";

const Option = ({ percentage, label, gradient, onSelect }) => {
  return (
    <li className="option" data-percentage={percentage} onClick={onSelect}>
      <input className="radio-custom" name="radio-group" type="radio" />
      <em className="radio-custom-label"></em>
      <div className="progressWrapper">
        <div className="labelInfo">
          <strong>{label}</strong>
          <div className="progress-light-grey">
            <div
              className="progress-container progress-color progress-center"
              aria-valuenow={percentage}
              aria-valuemin="0"
              aria-valuemax="100"
              style={{ "--value": percentage, background: gradient }}
            >
              <span>{percentage}%</span>
            </div>
          </div>
        </div>
        <label>{percentage}%</label>
      </div>
    </li>
  );
};

const Progress = (props) => {
  
 
  const [selectedOption, setSelectedOption] = useState({
    text: "Lead",
    percentage: 10,  
    background: "linear-gradient(90deg, #9E77ED 10%, transparent 10%)", 
  });

  const [dropdownOpen, setDropdownOpen] = useState(false);

  const toggleOptions = () => {
    // Close any open dropdowns
    const openDropdowns = document.querySelectorAll(".options.active");
    openDropdowns.forEach((dropdown) => dropdown.classList.remove("active"));
  
    // Open or close the current dropdown
    setDropdownOpen((prevState) => !prevState);
  };

  const selectOption = (event) => {
    const selectedOption = event.currentTarget;
    const radioInput = selectedOption.querySelector('input[type="radio"]');

    if (radioInput) {
      radioInput.checked = true;

      const selectedText =
        selectedOption.querySelector(".labelInfo strong").textContent;
      const selectedPercentage = selectedOption.getAttribute("data-percentage");

      const progressBar = selectedOption.querySelector(".progress-container");
      const computedStyle = getComputedStyle(progressBar);
      const selectedBackground = computedStyle.getPropertyValue("background");

      setSelectedOption({
        text: `${selectedText}`,
        percentage: selectedPercentage,
        background: selectedBackground,
      });

      const allOptions = document.querySelectorAll(".options .option");
      allOptions.forEach((option) => option.classList.remove("active"));

      selectedOption.classList.add("active");
      setDropdownOpen(false);
    }
  };

  return (
    <div className="select-menu">
      <div className="select-btn" onClick={toggleOptions}>
       <CircleProgressBar percentage = {selectedOption.percentage} selectlabel= {selectedOption.text}/>
        <ChevronDown color="#98A2B3" size={16} />
      </div>
      <ul className={`options ${dropdownOpen ? "active" : ""}`}>
        {[
          {
            percentage: 10,
            label: "Lead",
            gradient: "linear-gradient(90deg, #9E77ED 10%, transparent 10%)",
          },
          {
            percentage: 20,
            label: props.progressName1,
            gradient: `linear-gradient(90deg, #9E77ED ${props.progressPercentage1}%, transparent ${props.progressPercentage1}%)`,
          },
          {
            percentage: 40,
            label: "Proposal sent",
            gradient: "linear-gradient(90deg, #9E77ED 40%, transparent 40%)",
          },
          {
            percentage: 60,
            label: "Negotiation",
            gradient: "linear-gradient(90deg, #9E77ED 60%, transparent 60%)",
          },
          {
            percentage: 80,
            label: "Awaiting approval",
            gradient: "linear-gradient(90deg, #9E77ED 80%, transparent 80%)",
          },
          // Add more options if needed
        ].map((option) => (
          <Option
            key={option.percentage}
            percentage={option.percentage}
            label={option.label}
            gradient={option.gradient}
            onSelect={selectOption}
          />
        ))}
      </ul>
    </div>
  );
};

export default Progress;
